import React from "react";
import { Flex, Text } from "../../../_compat";
import * as Yup from "yup";
import { type TestContext, ValidationError } from "yup";

export type Auth0PasswordStrengthProps = {
    value: string;
    show: boolean;
    schema: Yup.StringSchema<string, Yup.AnyObject, undefined, "">;
};

const Auth0PasswordStrength = ({
    value,
    show,
    schema,
}: Auth0PasswordStrengthProps) => {
    const condition = (con: boolean) => {
        return con ? "green" : "red";
    };

    if (!show) return null;

    return (
        <Flex flexDirection={"column"} p={10} fontSize={"sm"}>
            {schema.tests.map((test, index) => {
                const msg = test.OPTIONS?.message;
                const name = test.OPTIONS?.name;

                if (name === "required") return null;
                const ctx: Partial<TestContext<any>> = {
                    path: "password",
                    parent: {},
                    options: {},
                    originalValue: value,
                    resolve: (val: any) => val,
                    createError: (params) =>
                        new ValidationError(
                            params?.message?.toString() ?? "",
                            value,
                            "password"
                        ),
                };

                const testFn = test.OPTIONS?.test as (
                    this: any,
                    value: any
                ) => any;
                const testing = testFn?.call(ctx, value);

                return (
                    <Flex
                        flexDirection={"row"}
                        alignItems={"center"}
                        gap={10}
                        key={index}
                    >
                        <Text color={condition(!!testing)}>
                            {testing ? "\u2713" : "\u2717"}
                        </Text>
                        {typeof msg === "string" ? (
                            <Text fontSize={13}>{msg}</Text>
                        ) : (
                            <Text>{name}</Text>
                        )}
                    </Flex>
                );
            })}
        </Flex>
    );
};

export default Auth0PasswordStrength;
